enum Shape {
    Circle(f64),
    Rect { w: f64, h: f64 },
    Triangle(f64, f64),
}

fn area(s: &Shape) -> f64 {
    match s {
        Shape::Circle(r)       => 3.14159 * r * r,
        Shape::Rect { w, h }   => w * h,
        Shape::Triangle(b, h)  => 0.5 * b * h,
    }
}

// Top-level statements - no fn main() needed
let shapes = [Shape::Circle(3.0), Shape::Rect { w: 4.0, h: 5.0 }, Shape::Triangle(6.0, 2.0)]
for s in shapes {
    println!("area = {:.2}", area(&s))
}
